NAMESPACE_UUID = uuid.UUID("6ba7b810-9dad-11d1-80b4-00c04fd430c8")

@F.udf(returnType=T.StringType())
def uuid5_from_text(txt):
    if txt is None:
        return None
    return str(uuid.uuid5(NAMESPACE_UUID, str(txt).strip().lower()))

def clean(col):
    return F.when(
        col.isNull() |
        (F.trim(col) == "") |
        (F.lower(F.trim(col)).isin("undefined", "null", "none")),
        None
    ).otherwise(F.trim(col))

def parse_dt(col):
    return F.coalesce(
        F.to_timestamp(col, "dd/MM/yyyy HH:mm:ss"),
        F.to_timestamp(col, "dd/MM/yyyy"),
        F.to_timestamp(col, "yyyy-MM-dd HH:mm:ss"),
        F.to_timestamp(col, "yyyy-MM-dd")
